import React from 'react';
import { Check, Star } from 'lucide-react';
import { Lesson } from '../types';

interface LessonNodeProps {
  lesson: Lesson;
  index: number;
  onStart: (lesson: Lesson) => void;
}

const LessonNode: React.FC<LessonNodeProps> = ({ lesson, index, onStart }) => {
  // Horizontal offset to create the winding path effect
  const offset = [0, 40, 60, 40, 0, -40, -60, -40][index % 8];

  const colors = {
    completed: 'bg-[#58cc02] border-[#46a302] text-white',
    available: 'bg-[#58cc02] border-[#46a302] text-white',
    locked: 'bg-[#e5e5e5] border-[#afafaf] text-[#afafaf]'
  };

  return (
    <div className="relative mb-8 flex flex-col items-center group" style={{ marginLeft: `${offset}px` }}>
      <button
        disabled={lesson.status === 'locked'}
        onClick={() => onStart(lesson)}
        className={`duo-button relative h-20 w-20 rounded-full border-b-[6px] transition-transform flex items-center justify-center ${
          colors[lesson.status]
        } ${lesson.status !== 'locked' ? 'hover:scale-105 active:translate-y-1' : ''}`}
      >
        {lesson.status === 'completed' ? (
          <Check size={32} strokeWidth={4} />
        ) : (
          <Star size={32} fill="currentColor" />
        )}

        {lesson.status === 'available' && (
            <div className="absolute -top-12 bg-white text-[#4b4b4b] px-3 py-1 rounded-xl shadow-lg border-2 border-[#e5e5e5] font-bold text-sm whitespace-nowrap animate-bounce">
                START!
                <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-3 h-3 bg-white border-b-2 border-r-2 border-[#e5e5e5] rotate-45"></div>
            </div>
        )}
      </button>
      <span className="mt-2 font-bold text-[#4b4b4b]">{lesson.title}</span>
    </div>
  );
};

export default LessonNode;

import React, { useState, useEffect } from 'react';
import { X, Volume2, Info, CheckCircle2, XCircle } from 'lucide-react';
import { Exercise, ExerciseType, Language } from '../types';
import { getExplanation } from '../services/geminiService';

interface ExerciseScreenProps {
  exercises: Exercise[];
  language: Language;
  onClose: (completed: boolean) => void;
  onLoseHeart: () => void;
}

const ExerciseScreen: React.FC<ExerciseScreenProps> = ({ exercises, language, onClose, onLoseHeart }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [inputText, setInputText] = useState('');
  const [isAnswered, setIsAnswered] = useState(false);
  const [isCorrect, setIsCorrect] = useState(false);
  const [explanation, setExplanation] = useState<string | null>(null);
  const [loadingExplanation, setLoadingExplanation] = useState(false);

  const currentExercise = exercises[currentIndex];
  const progress = ((currentIndex) / exercises.length) * 100;

  const handleSubmit = async () => {
    const answer = currentExercise.type === ExerciseType.MULTIPLE_CHOICE ? selectedOption : inputText;
    if (!answer) return;

    const correct = answer.toLowerCase().trim() === currentExercise.correctAnswer.toLowerCase().trim();
    setIsCorrect(correct);
    setIsAnswered(true);

    if (!correct) {
      onLoseHeart();
      setLoadingExplanation(true);
      const expl = await getExplanation(language, currentExercise, answer);
      setExplanation(expl);
      setLoadingExplanation(false);
    }
  };

  const handleNext = () => {
    if (currentIndex < exercises.length - 1) {
      setCurrentIndex(currentIndex + 1);
      setIsAnswered(false);
      setSelectedOption(null);
      setInputText('');
      setExplanation(null);
    } else {
      onClose(true);
    }
  };

  if (!currentExercise) return null;

  return (
    <div className="fixed inset-0 z-[100] flex flex-col bg-white">
      {/* Header */}
      <div className="flex h-20 items-center gap-4 px-4 lg:px-20">
        <button onClick={() => onClose(false)} className="text-[#afafaf] hover:text-[#4b4b4b]">
          <X size={32} />
        </button>
        <div className="h-4 flex-1 rounded-full bg-[#e5e5e5]">
          <div 
            className="h-full rounded-full bg-[#58cc02] transition-all duration-500" 
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {/* Main Content */}
      <main className="flex flex-1 flex-col items-center justify-center px-4 lg:px-20 max-w-4xl mx-auto w-full">
        <h2 className="mb-8 text-left w-full text-2xl font-bold lg:text-3xl">
          {currentExercise.type === ExerciseType.TRANSLATION ? 'Write this in English' : 'Choose the correct meaning'}
        </h2>

        <div className="mb-12 flex w-full flex-col items-start gap-8">
          <div className="flex items-center gap-4">
            <div className="h-24 w-24 overflow-hidden rounded-2xl bg-[#e5e5e5]">
              <img src={`https://picsum.photos/seed/${currentExercise.id}/200`} alt="Prompt visual" className="h-full w-full object-cover" />
            </div>
            <div className="relative rounded-2xl border-2 border-[#e5e5e5] p-4 font-semibold text-lg">
              <div className="absolute -left-2 top-1/2 -translate-y-1/2 w-3 h-3 bg-white border-l-2 border-b-2 border-[#e5e5e5] rotate-45"></div>
              {currentExercise.prompt}
              <button className="ml-2 inline-block text-[#1cb0f6]">
                <Volume2 size={20} />
              </button>
            </div>
          </div>

          {currentExercise.type === ExerciseType.MULTIPLE_CHOICE && (
            <div className="grid w-full grid-cols-1 gap-3 sm:grid-cols-2">
              {currentExercise.options?.map((option) => (
                <button
                  key={option}
                  disabled={isAnswered}
                  onClick={() => setSelectedOption(option)}
                  className={`duo-button flex items-center rounded-2xl border-2 border-b-4 p-4 text-left font-bold transition-all ${
                    selectedOption === option
                      ? 'border-[#84d8ff] bg-[#ddf4ff] text-[#1cb0f6]'
                      : 'border-[#e5e5e5] text-[#4b4b4b] hover:bg-[#f7f7f7]'
                  } ${isAnswered && option === currentExercise.correctAnswer ? 'border-[#58cc02] bg-[#d7ffb8]' : ''}`}
                >
                  {option}
                </button>
              ))}
            </div>
          )}

          {currentExercise.type === ExerciseType.TRANSLATION && (
            <div className="w-full">
              <textarea
                disabled={isAnswered}
                value={inputText}
                onChange={(e) => setInputText(e.target.value)}
                placeholder="Type in English..."
                className="w-full rounded-2xl border-2 border-[#e5e5e5] bg-[#f7f7f7] p-6 text-xl focus:border-[#1cb0f6] focus:outline-none min-h-[150px]"
              />
            </div>
          )}
        </div>
      </main>

      {/* Footer / Feedback */}
      <footer className={`h-36 lg:h-44 w-full flex items-center justify-between px-4 lg:px-20 transition-colors ${
        !isAnswered ? 'bg-white border-t-2 border-[#e5e5e5]' : (isCorrect ? 'bg-[#d7ffb8]' : 'bg-[#ffdfe0]')
      }`}>
        {isAnswered ? (
          <div className="flex flex-1 items-center gap-4">
            {isCorrect ? (
              <CheckCircle2 size={64} className="text-[#58cc02]" fill="#fff" />
            ) : (
              <XCircle size={64} className="text-[#ff4b4b]" fill="#fff" />
            )}
            <div className="flex-1">
              <h3 className={`text-xl font-black ${isCorrect ? 'text-[#58cc02]' : 'text-[#ff4b4b]'}`}>
                {isCorrect ? 'Excellent!' : 'Correct solution:'}
              </h3>
              <p className={`font-bold ${isCorrect ? 'text-[#58cc02]' : 'text-[#ff4b4b]'}`}>
                {isCorrect ? '' : currentExercise.correctAnswer}
              </p>
              {!isCorrect && explanation && (
                <div className="mt-1 flex items-start gap-1 max-w-xl">
                  <Info size={16} className="mt-1 flex-shrink-0" />
                  <p className="text-sm italic opacity-80">{explanation}</p>
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="flex-1" />
        )}

        <button
          onClick={isAnswered ? handleNext : handleSubmit}
          className={`duo-button w-full sm:w-48 rounded-2xl py-3 font-black tracking-widest text-white transition-all ${
            !isAnswered 
              ? ( (currentExercise.type === ExerciseType.MULTIPLE_CHOICE ? selectedOption : inputText) ? 'bg-[#58cc02]' : 'bg-[#e5e5e5] cursor-not-allowed')
              : (isCorrect ? 'bg-[#58cc02]' : 'bg-[#ff4b4b]')
          }`}
        >
          {isAnswered ? 'CONTINUE' : 'CHECK'}
        </button>
      </footer>
    </div>
  );
};

export default ExerciseScreen;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import TopBar from './components/TopBar';
import LessonNode from './components/LessonNode';
import ExerciseScreen from './components/ExerciseScreen';
import { UserStats, Unit, Lesson, Language } from './types';
import { INITIAL_UNITS } from './constants';
import { generateExercises } from './services/geminiService';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('learn');
  const [stats, setStats] = useState<UserStats>({
    xp: 0,
    streak: 5,
    gems: 420,
    hearts: 5,
    level: 1,
    selectedLanguage: 'Spanish'
  });

  const [units, setUnits] = useState<Unit[]>(INITIAL_UNITS);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [loading, setLoading] = useState(false);

  const handleStartLesson = async (lesson: Lesson) => {
    setLoading(true);
    try {
      // Find which unit this lesson belongs to for context
      const unit = units.find(u => u.lessons.some(l => l.id === lesson.id));
      const exercises = await generateExercises(stats.selectedLanguage, unit?.title || 'Basics', stats.level);

      setActiveLesson({
        ...lesson,
        exercises
      });
    } catch (error) {
      console.error("Error generating exercises", error);
      alert("Oops! Gemini failed to generate exercises. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleLessonFinish = (completed: boolean) => {
    if (completed && activeLesson) {
      setStats(prev => ({
        ...prev,
        xp: prev.xp + 15,
        gems: prev.gems + 10
      }));

      // Update unit progress
      setUnits(prevUnits => prevUnits.map(unit => ({
        ...unit,
        lessons: unit.lessons.map((l, i) => {
          if (l.id === activeLesson.id) {
            return { ...l, status: 'completed' as const };
          }
          // Unlock next lesson
          const prevLesson = unit.lessons[i-1];
          if (prevLesson?.id === activeLesson.id && l.status === 'locked') {
            return { ...l, status: 'available' as const };
          }
          return l;
        })
      })));
    }
    setActiveLesson(null);
  };

  const handleLoseHeart = () => {
    setStats(prev => ({
      ...prev,
      hearts: Math.max(0, prev.hearts - 1)
    }));
  };

  return (
    <div className="min-h-screen bg-white pb-24 lg:pb-0 lg:pl-64">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <TopBar stats={stats} />

      <main className="mx-auto max-w-2xl px-4 py-10">
        {activeTab === 'learn' && (
          <div className="flex flex-col items-center">
            {units.map((unit) => (
              <div key={unit.id} className="w-full mb-12">
                <div className="mb-8 rounded-2xl bg-[#58cc02] p-6 text-white shadow-lg">
                  <h2 className="text-xl font-black uppercase tracking-wider">{unit.title}</h2>
                  <p className="font-bold opacity-80">{unit.description}</p>
                </div>

                <div className="flex flex-col items-center gap-4">
                  {unit.lessons.map((lesson, idx) => (
                    <LessonNode 
                      key={lesson.id} 
                      lesson={lesson} 
                      index={idx}
                      onStart={handleStartLesson}
                    />
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'leaderboard' && (
          <div className="flex flex-col items-center py-20 text-center">
            <img src="https://picsum.photos/seed/shield/200" className="w-32 h-32 mb-6 rounded-full" />
            <h2 className="text-2xl font-black text-[#4b4b4b]">Unlock Leaderboards!</h2>
            <p className="text-[#afafaf] font-bold mt-2">Complete 10 more lessons to compete with others.</p>
          </div>
        )}

        {activeTab === 'shop' && (
          <div className="grid grid-cols-1 gap-4">
            <h2 className="text-2xl font-black mb-4">Shop</h2>
            <div className="border-2 border-[#e5e5e5] rounded-2xl p-6 flex items-center justify-between">
              <div>
                <h3 className="font-black text-xl">Refill Hearts</h3>
                <p className="text-[#afafaf] font-bold">Get back to full health.</p>
              </div>
              <button className="bg-[#1cb0f6] text-white px-6 py-2 rounded-xl font-black duo-button">450 Gems</button>
            </div>
          </div>
        )}

        {activeTab === 'profile' && (
          <div className="flex flex-col items-center pt-10">
            <div className="w-32 h-32 rounded-full border-4 border-[#e5e5e5] overflow-hidden mb-4">
               <img src="https://picsum.photos/200" alt="Avatar" />
            </div>
            <h2 className="text-3xl font-black">Super User</h2>
            <p className="text-[#afafaf] font-bold">Joined May 2024</p>

            <div className="grid grid-cols-2 gap-4 w-full mt-10">
              <div className="border-2 border-[#e5e5e5] rounded-2xl p-4 flex gap-3 items-center">
                <div className="text-orange-500 font-bold text-2xl">🔥</div>
                <div>
                   <p className="font-black text-xl">{stats.streak}</p>
                   <p className="text-sm font-bold text-[#afafaf]">Day Streak</p>
                </div>
              </div>
              <div className="border-2 border-[#e5e5e5] rounded-2xl p-4 flex gap-3 items-center">
                <div className="text-blue-500 font-bold text-2xl">💎</div>
                <div>
                   <p className="font-black text-xl">{stats.gems}</p>
                   <p className="text-sm font-bold text-[#afafaf]">Total Gems</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Overlays */}
      {loading && (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-white bg-opacity-95">
          <Loader2 size={64} className="animate-spin text-[#58cc02]" />
          <h2 className="mt-6 text-2xl font-black text-[#58cc02]">Gemini is preparing your lesson...</h2>
          <p className="mt-2 text-[#afafaf] font-bold italic">"Consistency is key to mastery!"</p>
        </div>
      )}

      {activeLesson && activeLesson.exercises.length > 0 && (
        <ExerciseScreen 
          exercises={activeLesson.exercises} 
          language={stats.selectedLanguage}
          onClose={handleLessonFinish}
          onLoseHeart={handleLoseHeart}
        />
      )}
    </div>
  );
};

export default App;

export type Language = 'Spanish' | 'French' | 'German' | 'Japanese' | 'Italian';

export enum ExerciseType {
  TRANSLATION = 'TRANSLATION',
  MULTIPLE_CHOICE = 'MULTIPLE_CHOICE',
  LISTENING = 'LISTENING',
  SPEAKING = 'SPEAKING'
}

export interface Exercise {
  id: string;
  type: ExerciseType;
  prompt: string;
  correctAnswer: string;
  options?: string[];
  audioUrl?: string;
  difficulty: number;
}

export interface Unit {
  id: string;
  title: string;
  description: string;
  lessons: Lesson[];
}

export interface Lesson {
  id: string;
  title: string;
  exercises: Exercise[];
  status: 'locked' | 'available' | 'completed';
}

export interface UserStats {
  xp: number;
  streak: number;
  gems: number;
  hearts: number;
  level: number;
  selectedLanguage: Language;
  displayName: string;
  avatarUrl: string;
}

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import TopBar from './components/TopBar';
import LessonNode from './components/LessonNode';
import ExerciseScreen from './components/ExerciseScreen';
import { UserStats, Unit, Lesson, Language } from './types';
import { INITIAL_UNITS } from './constants';
import { generateExercises } from './services/geminiService';
import { Loader2, Pencil, Check, X, Camera } from 'lucide-react';

const AVATAR_OPTIONS = [
  'https://api.dicebear.com/7.x/bottts/svg?seed=Felix',
  'https://api.dicebear.com/7.x/bottts/svg?seed=Buddy',
  'https://api.dicebear.com/7.x/bottts/svg?seed=Luna',
  'https://api.dicebear.com/7.x/bottts/svg?seed=Zoe',
  'https://api.dicebear.com/7.x/bottts/svg?seed=Max',
  'https://api.dicebear.com/7.x/bottts/svg?seed=Shadow',
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('learn');
  const [stats, setStats] = useState<UserStats>({
    xp: 0,
    streak: 5,
    gems: 420,
    hearts: 5,
    level: 1,
    selectedLanguage: 'Spanish',
    displayName: 'Super Learner',
    avatarUrl: AVATAR_OPTIONS[0]
  });

  const [units, setUnits] = useState<Unit[]>(INITIAL_UNITS);
  const [activeLesson, setActiveLesson] = useState<Lesson | null>(null);
  const [loading, setLoading] = useState(false);

  // Profile editing state
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [tempName, setTempName] = useState(stats.displayName);
  const [tempAvatar, setTempAvatar] = useState(stats.avatarUrl);

  const handleStartLesson = async (lesson: Lesson) => {
    setLoading(true);
    try {
      const unit = units.find(u => u.lessons.some(l => l.id === lesson.id));
      const exercises = await generateExercises(stats.selectedLanguage, unit?.title || 'Basics', stats.level);

      setActiveLesson({
        ...lesson,
        exercises
      });
    } catch (error) {
      console.error("Error generating exercises", error);
      alert("Oops! Gemini failed to generate exercises. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleLessonFinish = (completed: boolean) => {
    if (completed && activeLesson) {
      setStats(prev => ({
        ...prev,
        xp: prev.xp + 15,
        gems: prev.gems + 10
      }));

      setUnits(prevUnits => prevUnits.map(unit => ({
        ...unit,
        lessons: unit.lessons.map((l, i) => {
          if (l.id === activeLesson.id) {
            return { ...l, status: 'completed' as const };
          }
          const prevLesson = unit.lessons[i-1];
          if (prevLesson?.id === activeLesson.id && l.status === 'locked') {
            return { ...l, status: 'available' as const };
          }
          return l;
        })
      })));
    }
    setActiveLesson(null);
  };

  const handleLoseHeart = () => {
    setStats(prev => ({
      ...prev,
      hearts: Math.max(0, prev.hearts - 1)
    }));
  };

  const saveProfile = () => {
    setStats(prev => ({
      ...prev,
      displayName: tempName,
      avatarUrl: tempAvatar
    }));
    setIsEditingProfile(false);
  };

  const cancelProfileEdit = () => {
    setTempName(stats.displayName);
    setTempAvatar(stats.avatarUrl);
    setIsEditingProfile(false);
  };

  return (
    <div className="min-h-screen bg-white pb-24 lg:pb-0 lg:pl-64">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <TopBar stats={stats} />

      <main className="mx-auto max-w-2xl px-4 py-10">
        {activeTab === 'learn' && (
          <div className="flex flex-col items-center">
            {units.map((unit) => (
              <div key={unit.id} className="w-full mb-12">
                <div className="mb-8 rounded-2xl bg-[#58cc02] p-6 text-white shadow-lg">
                  <h2 className="text-xl font-black uppercase tracking-wider">{unit.title}</h2>
                  <p className="font-bold opacity-80">{unit.description}</p>
                </div>

                <div className="flex flex-col items-center gap-4">
                  {unit.lessons.map((lesson, idx) => (
                    <LessonNode 
                      key={lesson.id} 
                      lesson={lesson} 
                      index={idx}
                      onStart={handleStartLesson}
                    />
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'leaderboard' && (
          <div className="flex flex-col items-center py-20 text-center">
            <img src="https://api.dicebear.com/7.x/bottts/svg?seed=Shield" className="w-32 h-32 mb-6 rounded-full" />
            <h2 className="text-2xl font-black text-[#4b4b4b]">Unlock Leaderboards!</h2>
            <p className="text-[#afafaf] font-bold mt-2">Complete 10 more lessons to compete with others.</p>
          </div>
        )}

        {activeTab === 'shop' && (
          <div className="grid grid-cols-1 gap-4">
            <h2 className="text-2xl font-black mb-4">Shop</h2>
            <div className="border-2 border-[#e5e5e5] rounded-2xl p-6 flex items-center justify-between">
              <div>
                <h3 className="font-black text-xl">Refill Hearts</h3>
                <p className="text-[#afafaf] font-bold">Get back to full health.</p>
              </div>
              <button className="bg-[#1cb0f6] text-white px-6 py-2 rounded-xl font-black duo-button">450 Gems</button>
            </div>
          </div>
        )}

        {activeTab === 'profile' && (
          <div className="flex flex-col items-center pt-10">
            {!isEditingProfile ? (
              <>
                <div className="group relative w-32 h-32 rounded-full border-4 border-[#e5e5e5] overflow-hidden mb-4">
                  <img src={stats.avatarUrl} alt="Avatar" className="w-full h-full bg-slate-100" />
                  <button 
                    onClick={() => setIsEditingProfile(true)}
                    className="absolute inset-0 bg-black bg-opacity-40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity text-white"
                  >
                    <Camera size={24} />
                  </button>
                </div>
                <div className="flex items-center gap-2 mb-1">
                  <h2 className="text-3xl font-black">{stats.displayName}</h2>
                  <button 
                    onClick={() => setIsEditingProfile(true)}
                    className="p-1 text-[#afafaf] hover:text-[#1cb0f6] transition-colors"
                  >
                    <Pencil size={20} />
                  </button>
                </div>
                <p className="text-[#afafaf] font-bold">Joined May 2024</p>
              </>
            ) : (
              <div className="w-full bg-white border-2 border-[#e5e5e5] rounded-2xl p-8 flex flex-col items-center shadow-sm">
                <h3 className="text-xl font-black mb-6">Edit Profile</h3>

                <div className="mb-8 flex flex-col items-center">
                  <p className="text-sm font-black text-[#afafaf] uppercase tracking-wider mb-4">Choose an Avatar</p>
                  <div className="grid grid-cols-3 gap-4 mb-6">
                    {AVATAR_OPTIONS.map((url) => (
                      <button
                        key={url}
                        onClick={() => setTempAvatar(url)}
                        className={`w-16 h-16 rounded-full border-4 overflow-hidden transition-all ${
                          tempAvatar === url ? 'border-[#1cb0f6] scale-110 shadow-md' : 'border-transparent hover:border-[#e5e5e5]'
                        }`}
                      >
                        <img src={url} alt="Avatar Option" className="w-full h-full bg-slate-50" />
                      </button>
                    ))}
                  </div>
                </div>

                <div className="w-full mb-8">
                  <label className="block text-sm font-black text-[#afafaf] uppercase tracking-wider mb-2">Display Name</label>
                  <input
                    type="text"
                    value={tempName}
                    onChange={(e) => setTempName(e.target.value)}
                    className="w-full p-4 border-2 border-[#e5e5e5] rounded-xl font-bold text-lg focus:border-[#1cb0f6] focus:outline-none transition-colors"
                    placeholder="Enter your name"
                  />
                </div>

                <div className="flex gap-4 w-full">
                  <button 
                    onClick={cancelProfileEdit}
                    className="flex-1 duo-button border-2 border-[#e5e5e5] p-3 rounded-xl font-black text-[#afafaf] flex items-center justify-center gap-2"
                  >
                    <X size={20} /> CANCEL
                  </button>
                  <button 
                    onClick={saveProfile}
                    className="flex-1 duo-button bg-[#58cc02] p-3 rounded-xl font-black text-white flex items-center justify-center gap-2"
                  >
                    <Check size={20} /> SAVE CHANGES
                  </button>
                </div>
              </div>
            )}

            <div className="grid grid-cols-2 gap-4 w-full mt-10">
              <div className="border-2 border-[#e5e5e5] rounded-2xl p-4 flex gap-3 items-center">
                <div className="text-orange-500 font-bold text-2xl">🔥</div>
                <div>
                   <p className="font-black text-xl">{stats.streak}</p>
                   <p className="text-sm font-bold text-[#afafaf]">Day Streak</p>
                </div>
              </div>
              <div className="border-2 border-[#e5e5e5] rounded-2xl p-4 flex gap-3 items-center">
                <div className="text-blue-500 font-bold text-2xl">💎</div>
                <div>
                   <p className="font-black text-xl">{stats.gems}</p>
                   <p className="text-sm font-bold text-[#afafaf]">Total Gems</p>
                </div>
              </div>
            </div>
