      {activeLesson && activeLesson.exercises.length > 0 && (
        <ExerciseScreen 
          exercises={activeLesson.exercises} 
          language={stats.selectedLanguage}
          onClose={handleLessonFinish}
          onLoseHeart={handleLoseHeart}
        />
      )}
