      setStats(prev => ({
        ...prev,
        xp: prev.xp + 15,
        gems: prev.gems + 10
      }));

      setUnits(prevUnits => prevUnits.map(unit => ({
        ...unit,
        lessons: unit.lessons.map((l, i) => {
