                   } else {
                     alert("Not enough gems!");
                   }
                }}
                className="bg-[#1cb0f6] text-white px-6 py-2 rounded-xl font-black duo-button"
              >
                450 Gems
              </button>
            </div>
          </div>
        )}

        {activeTab === 'profile' && (
