  id: string;
  title: string;
  description: string;
  lessons: Lesson[];
}

export interface Lesson {
  id: string;
  title: string;
  exercises: Exercise[];
  status: 'locked' | 'available' | 'completed';
}

export interface Badge {
  id: string;
  name: string;
  description: string;
  icon: string;
  earnedDate?: string;
}

export interface UserStats {
  xp: number;
  streak: number;
  gems: number;
  hearts: number;
  level: number;
  selectedLanguage: Language;
  displayName: string;
  avatarUrl: string;
  badges: Badge[];
}

